#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create block_allocator instance
    hexi::block_allocator<int, element_count> allocator;

    std::cout << "Block Allocator Demonstration\n";
    std::cout << "----------------------------\n";

    // Initially, the free list has element_count blocks
    std::cout << "Initial state: Free list contains " << element_count << " blocks\n";

    // Allocate all blocks to empty the free list
    int* allocated_blocks[element_count];
    for (size_t i = 0; i < element_count; ++i) {
        allocated_blocks[i] = allocator.allocate(i);
        std::cout << "Allocated block " << i << " - Address: " << allocated_blocks[i] << "\n";
    }

    std::cout << "After allocation: Free list is empty\n";

    // Deallocate one block to demonstrate push() operation
    allocator.deallocate(allocated_blocks[0]);
    std::cout << "Deallocated block 0 - push() adds it to the head of free list\n";

    // Allocate again to demonstrate pop() operation
    int* new_block = allocator.allocate(100);
    std::cout << "Allocated new block - pop() removes from head and returns it\n";
    std::cout << "New block address: " << new_block << "\n";

    // Deallocate remaining blocks
    for (size_t i = 1; i < element_count; ++i) {
        allocator.deallocate(allocated_blocks[i]);
    }

    std::cout << "Final state: All blocks deallocated, free list contains " << element_count << " blocks\n";
}
```

**Explanation:**

This implementation demonstrates the internal free list management of `block_allocator` by:

1. **Initial State**: The free list starts with `element_count` blocks as shown in the constructor
2. **Allocation Cycle**: 
   - `allocate()` calls `pop()` which removes blocks from the head of the free list
   - When the free list is empty, `new` is used to allocate additional memory
3. **Deallocation Cycle**:
   - `deallocate()` calls `push()` which adds blocks to the head of the free list
   - The `push()` operation links the block using the internal `next` pointer

The demonstration shows how the allocator efficiently reuses pre-allocated blocks through the free list mechanism before resorting to dynamic allocation.

