    // Check if the file buffer is in a valid state
    if (!buffer) {
        return {};
    }

    // Create a vector to store the preview data
    std::vector<uint8_t> data(bytes_to_preview);

    // Use the copy method to copy data without advancing the read pointer
    buffer.copy(data.data(), bytes_to_preview);

    // Return the vector containing the preview data
    return data;
