std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a buffer and buffer_write_adaptor for writing
    std::vector<uint8_t> buffer;
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Track total bytes written
    std::size_t total_written = 0;

    // Iterate through each chunk and write it
    for (const auto& chunk : chunks) {
        // Handle empty chunks edge case
        if (chunk.empty()) {
            continue;
        }

        // Check available space before writing
        std::size_t available_space = adaptor.free();

        // Handle insufficient space edge case
        if (available_space < chunk.size()) {
            // Only write what fits
            adaptor.write(chunk.data(), available_space);
            total_written += available_space;
            break; // Buffer is full
        } else {
            // Write the entire chunk
            adaptor.write(chunk.data(), chunk.size());
            total_written += chunk.size();
        }
    }

    // Return the total size written (final buffer size)
    return total_written;
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create a buffer_read_adaptor for reading
    hexi::pmc::buffer_read_adaptor<const std::vector<uint8_t>> adaptor(buffer);

    std::vector<uint8_t> result;

    // Read until buffer is empty
    while (adaptor.size() > 0) {
        // Determine how much to read (minimum of chunk_size and remaining data)
        std::size_t remaining = adaptor.size();
        std::size_t to_read = std::min(chunk_size, remaining);

        // Handle edge case: if to_read becomes 0 (shouldn't happen but safe to check)
        if (to_read == 0) {
            break;
        }

        // Read the data
        std::vector<uint8_t> temp(to_read);
        adaptor.read(temp.data(), to_read);

        // Append to result
        result.insert(result.end(), temp.begin(), temp.end());

        // Check remaining data after read (as per specification)
        // This is done implicitly by the while loop condition
    }

    return result;
}
