    double pressure;

    void serialise(auto& adaptor) const {
        // Serialization
        adaptor.write(sensor_id);

        // Convert and write temperatures
        for (const auto& temp : temperatures) {
            float converted_temp = hexi::endian::conditional_reverse(temp, std::endian::native, std::endian::little);
            adaptor.write(converted_temp);
        }

        // Convert and write pressure
        double converted_pressure = hexi::endian::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor.write(converted_pressure);
    }

    void serialise(auto& adaptor) {
        // Deserialization
        adaptor.read(sensor_id);

        // Read and convert temperatures
        temperatures.resize(adaptor.template read<uint32_t>()); // Assuming size is written first
        for (auto& temp : temperatures) {
            adaptor.read(temp);
            hexi::endian::little_to_native_inplace(temp);
        }

        // Read and convert pressure
        adaptor.read(pressure);
        hexi::endian::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);
    hexi::binary_stream stream(adaptor);
    stream.serialise(data);
    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);
    hexi::binary_stream stream(adaptor);
    MeasurementData data;
    stream.deserialise(data);
    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Extract null-terminated sensor name
    std::string_view sensor_name = stream.view();

    // Check if there's enough data for sensor_id (4 bytes)
    stream.enforce_read_bounds(4);

    // Read sensor_id directly
    uint32_t sensor_id;
    stream.read(&sensor_id, 1);

    // Skip remaining data
    stream.skip(buffer.size() - 4);

    return {sensor_id, sensor_name};
}
